#include "tn3270_protocol.h"

static const unsigned char ut3270_code_table[64] = {
    0x40, 0xC1, 0xC2, 0xC3, 0xC4, 0xC5, 0xC6, 0xC7,
    0xC8, 0xC9, 0x4A, 0x4B, 0x4C, 0x4D, 0x4E, 0x4F,
    0x50, 0xD1, 0xD2, 0xD3, 0xD4, 0xD5, 0xD6, 0xD7,
    0xD8, 0xD9, 0x5A, 0x5B, 0x5C, 0x5D, 0x5E, 0x5F,
    0x60, 0x61, 0xE2, 0xE3, 0xE4, 0xE5, 0xE6, 0xE7,
    0xE8, 0xE9, 0x6A, 0x6B, 0x6C, 0x6D, 0x6E, 0x6F,
    0xF0, 0xF1, 0xF2, 0xF3, 0xF4, 0xF5, 0xF6, 0xF7,
    0xF8, 0xF9, 0x7A, 0x7B, 0x7C, 0x7D, 0x7E, 0x7F
};

int ut3270_decode_baddr(unsigned char c1, unsigned char c2)
{
    if ((c1 & 0xc0) == 0x00)
        return (((int)c1 & 0x3f) << 8) | (int)c2;

    return (((int)c1 & 0x3f) << 6) | ((int)c2 & 0x3f);
}

void ut3270_encode_baddr(unsigned char *out, int addr, int rows, int cols)
{
    if ((rows * cols) > 0x1000)
        {
        out[0] = (unsigned char)((addr >> 8) & 0x3f);
        out[1] = (unsigned char)(addr & 0xff);
        }
    else
        {
        out[0] = ut3270_code_table[(addr >> 6) & 0x3f];
        out[1] = ut3270_code_table[addr & 0x3f];
        }
}

unsigned char ut3270_address_code(int value)
{
    return ut3270_code_table[value & 0x3f];
}
